import sys

MOD = 998244353

def main():
    import sys
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    M = int(data[1])
    S = data[2]

    # Precompute the positions of each character in S
    pos = {}
    for i, c in enumerate(S):
        if c not in pos:
            pos[c] = []
        pos[c].append(i)

    # dp[i][j] represents the number of ways to have a LCS of length j after considering first i characters of S
    dp = [[0] * (N + 1) for _ in range(M + 1)]
    dp[0][0] = 1

    for i in range(1, M + 1):
        for j in range(N + 1):
            # Case 1: current character is not part of LCS
            dp[i][j] = (dp[i][j] + dp[i - 1][j] * 25) % MOD
            # Case 2: current character matches some character in S
            for c in pos:
                if len(pos[c]) == 0:
                    continue
                for k in range(len(pos[c])):
                    idx = pos[c][k]
                    if idx >= j:
                        dp[i][j] = (dp[i][j] + dp[i - 1][j - 1]) % MOD

    # The answer for k is the number of strings with LCS exactly k
    ans = [0] * (N + 1)
    for k in range(N + 1):
        ans[k] = dp[M][k]

    print(' '.join(map(str, ans)))

if __name__ == '__main__':
    main()
